useEffect(() => {
  const topElement = document.querySelector(".top-element");
  const lowerElement = document.querySelector(".lower-element");

  // Function to trigger bounce effect
  function triggerBounce() {
    if (topElement) {
      console.log("Bounce triggered"); // Log when the bounce is triggered
      topElement.classList.add("bounce");
      setTimeout(() => {
        topElement.classList.remove("bounce");
        console.log("Bounce class removed"); // Log when the bounce is removed
      }, 600); // Match the bounce animation duration
    }
  }

  // Check if lowerElement exists
  if (!lowerElement) {
    console.error("Lower element not found!");
    return;
  }

  // Use MutationObserver to detect text content changes
  const observer = new MutationObserver((mutations) => {
    mutations.forEach((mutation) => {
      if (mutation.type === "childList") {
        console.log("Text changed in lower element"); // Log the text change
        triggerBounce();
      }
    });
  });

  // Start observing the lower element for text content changes
  observer.observe(lowerElement, {
    childList: true, // Observe direct children of lowerElement
    subtree: true, // Observe changes to all descendants
  });

  // Cleanup observer on unmount
  return () => {
    observer.disconnect();
  };
}, []);
